TEST_APPLY_SIGNING_KEY = "test-apply-signing-key"


def test_package_version_metadata_matches_pyproject():
    pyproject = tomllib.loads(
        (Path(__file__).parents[1] / "pyproject.toml").read_text()
    )
    lockfile = tomllib.loads((Path(__file__).parents[1] / "uv.lock").read_text())
    lock_version = next(
        package["version"]
        for package in lockfile["package"]
        if package["name"] == "axiom-encode"
    )

    assert pyproject["project"]["version"] == AXIOM_ENCODE_TEST_VERSION
    assert lock_version == AXIOM_ENCODE_TEST_VERSION


def test_current_encoder_affecting_changes_are_behind_version_bump():
    repo = Path(__file__).parents[1]
    try:
        _git(repo, "rev-parse", "--is-inside-work-tree")
    except subprocess.CalledProcessError:
        pytest.skip("version provenance check requires a git checkout")

    provenance = _require_axiom_encode_version_provenance(repo)

    assert provenance["version"] == AXIOM_ENCODE_TEST_VERSION


def test_source_id_encode_scopes_cfr_section_text_to_target_leaf(tmp_path):
    source = "\n\n".join(
        [
            "(b) State agency error rates.",
            "(2) Determination of payment error rates.",
            "(i) FNS shall calculate regressed error rates.",
            "(A) y1' = y1 + b1 (X1 - x1).",
            "(B) y2' = y2 + b2 (X2 - x2).",
            "(C) The regressed error rates are r1' = y1'/u and r2' = y2'/u.",
            "(D) The adjusted regressed payment error rate is r1'' + r2''.",
            "(d) State agencies' liabilities for payment error rates.",
        ]
    )

    scoped = _scoped_source_text_for_encode_source_id(
        source,
        source_id="us/regulation/7/275/23/b/2/i/C",
        policy_repo_path=tmp_path,
    )

    assert scoped.lstrip().startswith("(C) The regressed error rates")
    assert "r1' = y1'/u" in scoped
    assert "adjusted regressed payment error rate" not in scoped
    assert "liabilities for payment error rates" not in scoped


def test_colorado_snap_ecps_uses_absolute_member_relation_only():
    config = JURISDICTION_CONFIGS["us-co"]

    assert config.relation_id == "us:statutes/7/2012/j#relation.member_of_household"
    assert config.additional_relation_ids == ()


def test_arizona_snap_ecps_projects_boundary_inputs():
    config = JURISDICTION_CONFIGS["us-az"]
    values = {
        "snap_earned_income": [1000],
        "snap_unearned_income": [200],
        "snap_assets": [500],
        "snap_net_income": [750],
        "is_snap_eligible": [True],
        "snap_unit_size": [2],
        "snap_max_allotment": [536],
        "snap_min_allotment": [24],
        "snap_excess_shelter_expense_deduction": [150],
        "snap_dependent_care_deduction": [0],
    }

    assert config.program_relative_path.as_posix() == (
        "policies/des/faa5/na-eligibility-and-benefit-determination/"
        "fy-2026-benefit-calculation.yaml"
    )
    assert config.utility_allowance_labels == ()
    assert project_income_resource_inputs(config, values, 0) == {
        "snap_gross_monthly_earned_income": 1000.0,
        "snap_total_monthly_unearned_income": 200.0,
    }
    assert project_jurisdiction_household_inputs(config, values, 0) == {
        "na_net_income": 750.0,
        "na_budgetary_unit_is_eligible": True,
        "budgetary_unit_participant_count": 2,
        "thrifty_food_plan_amount_for_budgetary_unit_size": 536.0,
        "minimum_na_allotment": 24.0,
        "initial_month_proration_applies": False,
        "prorated_initial_month_na_benefit": 0,
        "snap_excess_shelter_deduction_for_net_income": 150.0,
    }


def _signed_manifest_payload(payload: dict) -> dict:
    _sign_applied_encoding_manifest(payload, TEST_APPLY_SIGNING_KEY)
    return payload


def _git(repo: Path, *args: str) -> subprocess.CompletedProcess[str]:
    return subprocess.run(
        ["git", "-C", str(repo), *args],
        check=True,
        capture_output=True,
        text=True,
    )


def _init_test_git_repo(repo: Path) -> None:
    repo.mkdir(parents=True)
    _git(repo, "init")
    _git(repo, "config", "user.email", "test@example.com")
    _git(repo, "config", "user.name", "Test User")


def _write_test_encoder_version(repo: Path, version: str) -> None:
    package_init = repo / "src/axiom_encode/__init__.py"
    package_init.parent.mkdir(parents=True, exist_ok=True)
    package_init.write_text(f'__version__ = "{version}"\n')
    (repo / "pyproject.toml").write_text(
        f'[project]\nname = "axiom-encode"\nversion = "{version}"\n'
    )
    (repo / "uv.lock").write_text(
        f'[[package]]\nname = "axiom-encode"\nversion = "{version}"\n'
    )


def _write_test_encoder_source(repo: Path, content: str) -> None:
    prompt = repo / "src/axiom_encode/prompts/encoder.py"
    prompt.parent.mkdir(parents=True, exist_ok=True)
    prompt.write_text(f'PROMPT = "{content}"\n')


