        axiom_rules_path = tmp_path / "axiom-rules-engine"
        axiom_rules_path.mkdir(parents=True)

        args = MagicMock()
        args.files = [rulespec_file]
        args.json = False
        args.skip_reviewers = False
        args.oracle = None
